const axios = require("axios");
const constants = require("./constants");

class GenericResource {
  constructor(configFn) {
    this._configFn = configFn;
    this.config = {};
    this.resource = "";
  }

  loadConfig = () => {
    this.config = this._configFn();
    let envURL =
      this.config.environment === constants.PRODUCTION
        ? constants.PRODUCTION_URL
        : constants.SANDBOX_URL;

    axios.defaults.baseURL = `${envURL}/api/${this.config.version}`;
    axios.defaults.headers.common["access_token"] = this.config.apiKey;
    axios.defaults.headers.common["Content-Type"] = "application/json";
  };

  /**
   * Obtém do Asaas um registro.
   * @param {String} id Identificador do registo no Asaas.
   * @returns {Promise} Promise, se resolver, será retornado os dados do registro solicitado.
   */
  get = (id) => {
    this.loadConfig();

    if (this.config.debug) {
      console.debug("*** GET ***");
      console.debug("* Resource: ", this.resource);
      console.debug("* Id: ", id);
    }

    return axios.get(`${this.resource}/${id}`);
  };

  /**
   * Obtém uma lista de registros do Asaas.
   * @param {Object} params Parâmetros para o filtro dos registros.
   * @returns {Promise} Promise, se resolver, será retornado um JSON com informações sobre a paginação e registros da página solicitada.
   */
  list = (params) => {
    this.loadConfig();

    if (this.config.debug) {
      console.debug("*** LIST ***");
      console.debug("* Resource: ", this.resource);
      console.debug("* Params: ", params);
    }

    let url = this.resource;

    if (params && Object.getOwnPropertyNames(params).length > 0) {
      let props = Object.getOwnPropertyNames(params);
      let filters = "?";

      for (let i = 0; i < props.length; i++) {
        let prop = props[i];

        if (i > 0) {
          filters = `${filters}&`;
        }
        filters = `${filters}${prop}=${params[prop]}`;
      }

      url = `${url}${filters}`;
    }

    return axios.get(url);
  };

  /**
   * Cria no Asaas um novo registro.
   * @param {Object} obj Objeto JSON com os dados do registo.
   * @returns {Promise} Promise, se resolver, será retornado os dados do registro criado.
   */
  post = (obj) => {
    this.loadConfig();

    if (this.config.debug) {
      console.debug("*** POST ***");
      console.debug("* Resource: ", this.resource);
      console.debug("* Object: ", JSON.stringify(obj));
    }

    return axios.post(this.resource, obj);
  };

  /**
   * Altera um registro na base do Asaas.
   * @param {String} id Identificador do registro retornado pelo Asaas.
   * @param {Object} obj Objeto JSON com os dados do registro.
   * @returns {Promise} Promise, se resolver, será retornado todos os dados do registro.
   */
  put = (id, obj) => {
    this.loadConfig();

    if (this.config.debug) {
      console.debug("*** PUT ***");
      console.debug("* Resource: ", this.resource);
      console.debug("* Id: ", id);
      console.debug("* Object: ", JSON.stringify(obj));
    }

    return axios.post(`${this.resource}/${id}`, obj);
  };

  /**
   * Remove um registro da base do Asaas.
   * @param {String} id Identificador do registro retornado pelo Asaas.
   * @returns {Promise} Promise, se resolver, será retornado um objeto JSON com o Id do registro removido e a flag deleted = true.
   */
  delete = (id) => {
    this.loadConfig();

    if (this.config.debug) {
      console.debug("*** DELETE ***");
      console.debug("* Resource: ", this.resource);
      console.debug("* Id: ", id);
    }

    return axios.delete(`${this.resource}/${id}`);
  };

  /**
   * Restaura um registro deletado na base do Asaas.
   * @param {String} id Identificador do registro retornado pelo Asaas.
   * @returns {Promise} Promise, se resolver, será retornado um objeto JSON com o Id do registro removido e a flag deleted = true.
   */
  restore = (id) => {
    this.loadConfig();

    if (this.config.debug) {
      console.debug("*** RESTORE ***");
      console.debug("* Resource: ", this.resource);
      console.debug("* Id: ", id);
    }

    return axios.post(`${this.resource}/${id}/restore`);
  };

  /**
   * Estornar cobranças via cartão de crédito recebidas ou confirmadas.
   * @param {String} id Identificador do registro retornado pelo Asaas.
   * @returns {Promise} Promise, se resolver, será retornado um objeto JSON com o Id do registro estornado e outras informações.
   */
  refund = (id) => {
    this.loadConfig();

    if (this.config.debug) {
      console.debug("*** REFUND ***");
      console.debug("* Resource: ", `${this.resource}/refund`);
      console.debug("* Id: ", id);
    }

    if (this.resource != "/payments") {
      let promise = new Promise((resolve, reject) => {
        reject("Asaas permite estornar apenas cobranças");
      });

      return promise;
    }
    return axios.post(`${this.resource}/${id}/refund`);
  };
}

module.exports = GenericResource;
